import{_ as t}from"./chunks/logo.PPNoggWL.js";import{_ as s,o as e,c as i,ag as o}from"./chunks/framework.DQQHyi2x.js";const m=JSON.parse('{"title":"Configurations Introduction","description":"","frontmatter":{"layout":"doc","next":{"text":"Core.jsonc","link":"/pages/configurations/core"},"prev":{"text":"Troubleshooting","link":"/pages/installation/troubleshooting"}},"headers":[],"relativePath":"pages/configurations/index.md","filePath":"pages/configurations/index.md"}'),n={name:"pages/configurations/index.md"};function r(l,a,c,h,d,p){return e(),i("div",null,[...a[0]||(a[0]=[o('<img src="'+t+`" alt="AtmosphericX Logo" width="200" style="display:block;margin:0 auto;"><small class="page-author">Written By: <b>KiyoWx</b> &amp; <b>StarflightWx</b></small><br><small class="last-updated">Last Updated: <b>Feb 27th, 2026</b></small><br><h1 id="configurations-introduction" tabindex="-1">Configurations Introduction <a class="header-anchor" href="#configurations-introduction" aria-label="Permalink to &quot;Configurations Introduction&quot;">​</a></h1><hr><p>AtmosphericX configuration ranges from simple tweaks to advanced customizations. Core settings are stored in <code>.jsonc</code> files located in the configurations directory, making it easy to edit your instance safely.</p><h2 id="what-is-jsonc" tabindex="-1">What is JSONC? <a class="header-anchor" href="#what-is-jsonc" aria-label="Permalink to &quot;What is JSONC?&quot;">​</a></h2><p>JSONC (JSON with Comments) is a variant of standard JSON that supports JavaScript style comments (<code>//</code> or <code>/* */</code>). It is ideal for configuration files because it allows you to document your settings without affecting functionality. <strong>Comments are ignored by the parser</strong>, so they won’t break the configuration.</p><h3 id="example-syntax" tabindex="-1">Example Syntax <a class="header-anchor" href="#example-syntax" aria-label="Permalink to &quot;Example Syntax&quot;">​</a></h3><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // This is a comment explaining the setting</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;example&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="why-atmosphericx-uses-jsonc" tabindex="-1">Why AtmosphericX Uses JSONC <a class="header-anchor" href="#why-atmosphericx-uses-jsonc" aria-label="Permalink to &quot;Why AtmosphericX Uses JSONC&quot;">​</a></h2><p>Using JSONC allows you to include comments directly in configuration files.<br> This helps you understand each setting before making changes, without needing separate documentation. It also makes collaboration easier, as notes and explanations can live alongside the settings.</p><div class="danger custom-block"><p class="custom-block-title">Mismatch Hashes</p><p>AtmosphericX uses <strong>SHA-1 checksums</strong> to verify that your configuration files match their expected version.</p><ul><li>Console warnings indicate a mismatch between your local config and the current release.</li><li>This is <strong>normal</strong> and simply validates your files.</li><li>Always ensure your configuration files are up to date with the latest AtmosphericX version to avoid unexpected behavior.</li></ul></div>`,15)])])}const f=s(n,[["render",r]]);export{m as __pageData,f as default};
